// Temporary CDP probe for BLP-4 / GitHub #36.
// Creates a long Live Preview host note with standard block embeds, scrolls it,
// and records whether the host editor scrollTop snaps back while BLP inline edit
// is enabled or disabled.
(async () => {
  co

nst wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
  const withTimeout = (promise, label, timeoutMs = 12000) =>
    Promise.race([
      promise,
      new Promise((_, reject) => window.setTimeout(() => reject(new Error(`${label} timed out`)), timeoutMs)),
    ]);
  const waitFor = async (fn, { timeoutMs = 12000, stepMs = 50 } = {}) => {
    const started = Date.now();
    while (Date.now() - started < timeoutMs) {
      const value = await fn();
      if (value) return value;
      await wait(stepMs);
    }
    return null;
  };
  const pluginId = "block-link-plus";
  const tmpFolder = "_blp_tmp";
  const sourcePath = `${tmpFolder}/issue36-scroll-source.md`;
  const hostPath = `${tmpFolder}/issue36-scroll-host.md`;
  const plugin = app.plugins.plugins[pluginId];
  if (!plugin) throw new Error("block-link-plus plugin is not loaded");

  const originalSettings = {
    inlineEditEnabled: plugin.settings.inlineEditEnabled,
    inlineEditBlock: plugin.settings.inlineEditBlock,
    inlineEditHeading: plugin.settings.inlineEditHeading,
    inlineEditFile: plugin.settings.inlineEditFile,
  };

  const ensureFolder = async (path) => {
    if (app.vault.getAbstractFileByPath(path)) return;
    try {
      await app.vault.createFolder(path);
    } catch {
      // ignore
    }
  };
  const upsert = async (path, content) => {
    let file = app.vault.getAbstractFileByPath(path);
    if (!file) file = await withTimeout(app.vault.create(path, content), `create ${path}`);
    else await withTimeout(app.vault.modify(file, content), `modify ${path}`);
    return file;
  };
  const setInlineEdit = async (enabled) => {
    plugin.settings.inlineEditEnabled = enabled;
    plugin.settings.inlineEditBlock = true;
    plugin.settings.inlineEditHeading = true;
    plugin.settings.inlineEditFile = false;
    await plugin.saveSettings?.();
    plugin.inlineEditEngine?.onSettingsChanged?.();
    await wait(250);
  };
  const openHost = async () => {
    const file = app.vault.getAbstractFileByPath(hostPath);
    const leaf = app.workspace.getLeaf(false);
    await withTimeout(
      leaf.setViewState({ type: "markdown", state: { file: hostPath, mode: "source" }, active: true }),
      "open host"
    );
    await waitFor(() => leaf.view?.file === file && leaf.view?.containerEl?.querySelector(".markdown-source-view"));
    return leaf;
  };
  const snapshot = (leaf, label) => {
    const cm = leaf.view?.editor?.cm;
    const scroller = cm?.scrollDOM ?? leaf.view?.containerEl?.querySelector(".cm-scroller");
    const root = leaf.view?.containerEl ?? document;
    return {
      label,
      activeFile: app.workspace.getActiveFile?.()?.path ?? null,
      mode: leaf.view?.getMode?.() ?? null,
      livePreviewClass: Boolean(root.querySelector(".markdown-source-view.is-live-preview")),
      scrollTop: scroller?.scrollTop ?? null,
      scrollHeight: scroller?.scrollHeight ?? null,
      clientHeight: scroller?.clientHeight ?? null,
      embedCount: root.querySelectorAll(".internal-embed.markdown-embed").length,
      activeInlineCount: root.querySelectorAll(".internal-embed.markdown-embed.blp-inline-edit-active").length,
      hostCount: root.querySelectorAll(".blp-inline-edit-host").length,
      rootCount: root.querySelectorAll(".blp-inline-edit-root").length,
      pendingCount: plugin.inlineEditEngine?.livePreviewObservers
        ? Array.from(plugin.inlineEditEngine.livePreviewObservers.values()).reduce((sum, entry) => sum + entry.pendingEmbeds.size, 0)
        : null,
      bodyClasses: document.body.className,
      isMobile: app.isMobile,
    };
  };
  const runScrollTrial = async (leaf, label) => {
    const cm = leaf.view?.editor?.cm;
    const scroller = cm?.scrollDOM ?? leaf.view?.containerEl?.querySelector(".cm-scroller");
    if (!scroller) throw new Error("missing CodeMirror scroller");
    const start = snapshot(leaf, `${label}:start`);
    const max = Math.max(0, scroller.scrollHeight - scroller.clientHeight);
    const targets = [
      Math.round(max * 0.15),
      Math.round(max * 0.35),
      Math.round(max * 0.55),
      Math.round(max * 0.75),
      Math.round(max * 0.9),
    ].filter((n) => n > 0);
    const samples = [start];
    for (const target of targets) {
      scroller.scrollTop = target;
      scroller.dispatchEvent(new Event("scroll", { bubbles: true }));
      await wait(350);
      samples.push(snapshot(leaf, `${label}:after-${target}`));
    }
    await wait(1000);
    samples.push(snapshot(leaf, `${label}:settled`));
    const scrollValues = samples.map((s) => s.scrollTop).filter((v) => typeof v === "number");
    const minAfterMove = scrollValues.slice(1).length ? Math.min(...scrollValues.slice(1)) : null;
    const last = samples[samples.length - 1];
    return {
      label,
      max,
      samples,
      snappedNearStart: typeof minAfterMove === "number" && minAfterMove <= Math.max(20, start.scrollTop + 20),
      finalNearStart: typeof last.scrollTop === "number" && last.scrollTop <= Math.max(20, start.scrollTop + 20),
    };
  };

  let previousFile = app.workspace.getActiveFile?.() ?? null;
  try {
    await ensureFolder(tmpFolder);
    const sourceLines = ["# Issue 36 scroll source", ""];
    for (let i = 1; i <= 36; i += 1) {
      sourceLines.push(`- Issue 36 embedded block ${i} ^i36b${i}`);
      for (let j = 1; j <= 4; j += 1) sourceLines.push(`  - child ${j} for block ${i}`);
      sourceLines.push(`  [date:: 2026-06-16T00:00:00] [updated:: 2026-06-16T00:00:00] [blp_sys:: 1] [blp_ver:: 2] ^i36tail${i}`);
      sourceLines.push("");
    }
    const hostLines = ["# Issue 36 scroll host", ""];
    for (let i = 1; i <= 36; i += 1) {
      hostLines.push(`Paragraph before embed ${i}.`);
      hostLines.push(`![[${sourcePath}#^i36b${i}]]`);
      hostLines.push(`Paragraph after embed ${i}.`);
      hostLines.push("");
    }
    await upsert(sourcePath, sourceLines.join("\n"));
    await upsert(hostPath, hostLines.join("\n"));

    await setInlineEdit(false);
    const disabledLeaf = await openHost();
    await waitFor(() => snapshot(disabledLeaf, "disabled-ready").embedCount >= 20, { timeoutMs: 15000 });
    const disabledBefore = snapshot(disabledLeaf, "disabled-before-scroll");
    const disabledTrial = await runScrollTrial(disabledLeaf, "inlineEditDisabled");

    await setInlineEdit(true);
    const enabledLeaf = await openHost();
    const mounted = await waitFor(() => {
      const s = snapshot(enabledLeaf, "enabled-wait-mounted");
      return s.activeInlineCount >= 20 && s.hostCount >= 20 && s.rootCount >= 20 ? s : null;
    }, { timeoutMs: 30000, stepMs: 100 });
    const enabledBefore = snapshot(enabledLeaf, "enabled-before-scroll");
    const enabledTrial = await runScrollTrial(enabledLeaf, "inlineEditEnabled");

    return {
      ok: true,
      pluginVersion: plugin.manifest?.version ?? null,
      obsidianVersion: app.metadataCache ? app.appId ?? null : null,
      appIsMobile: app.isMobile,
      viewport: { innerWidth, innerHeight, visualViewport: window.visualViewport ? { width: visualViewport.width, height: visualViewport.height, scale: visualViewport.scale } : null },
      originalSettings,
      disabledBefore,
      enabledMounted: mounted,
      enabledBefore,
      disabledTrial,
      enabledTrial,
      notes: {
        desktopRuntime: !app.isMobile,
        sourcePath,
        hostPath,
      },
    };
  } finally {
    try {
      plugin.settings.inlineEditEnabled = originalSettings.inlineEditEnabled;
      plugin.settings.inlineEditBlock = originalSettings.inlineEditBlock;
      plugin.settings.inlineEditHeading = originalSettings.inlineEditHeading;
      plugin.settings.inlineEditFile = originalSettings.inlineEditFile;
      await plugin.saveSettings?.();
      plugin.inlineEditEngine?.onSettingsChanged?.();
    } catch {
      // ignore
    }
    try {
      if (previousFile) await app.workspace.getLeaf(false).openFile(previousFile, { active: true });
    } catch {
      // ignore
    }
  }
})();

