diff --git a/.tmp/BLP-4/issue36-inline-mount-instrumented.js b/.tmp/BLP-4/issue36-inline-mount-instrumented.js
new file mode 100644
index 0000000000000000000000000000000000000000..b42a3b160d680b8e74941a3008f14b248de6e103
--- /dev/null
+++ b/.tmp/BLP-4/issue36-inline-mount-instrumented.js
@@ -0,0 +1,272 @@
+// Temporary CDP probe for BLP-4 / GitHub #36.
+// Instruments inline-edit mount while the host Live Preview editor is already scrolled.
+(async () => {
+  const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
+  const withTimeout = (promise, label, timeoutMs = 12000) =>
+    Promise.race([
+      promise,
+      new Promise((_, reject) => window.setTimeout(() => reject(new Error(`${label} timed out`)), timeoutMs)),
+    ]);
+  const waitFor = async (fn, { timeoutMs = 12000, stepMs = 50 } = {}) => {
+    const started = Date.now();
+    while (Date.now() - started < timeoutMs) {
+      const value = await fn();
+      if (value) return value;
+      await wait(stepMs);
+    }
+    return null;
+  };
+  const pluginId = "block-link-plus";
+  const plugin = app.plugins.plugins[pluginId];
+  if (!plugin) throw new Error("block-link-plus plugin is not loaded");
+
+  const tmpFolder = "_blp_tmp/issue-36-instrumented";
+  const sourcePath = `${tmpFolder}/source.md`;
+  const hostPath = `${tmpFolder}/host.md`;
+  const originalSettings = {
+    inlineEditEnabled: plugin.settings.inlineEditEnabled,
+    inlineEditBlock: plugin.settings.inlineEditBlock,
+    inlineEditHeading: plugin.settings.inlineEditHeading,
+    inlineEditFile: plugin.settings.inlineEditFile,
+  };
+  const previousFile = app.workspace.getActiveFile?.() ?? null;
+  const events = [];
+  const pushEvent = (event) => {
+    events.push({
+      at: Math.round(performance.now()),
+      ...event,
+      stack: String(new Error().stack || "")
+        .split("\n")
+        .slice(2, 7)
+        .join(" | "),
+    });
+  };
+  const ensureFolder = async (path) => {
+    if (app.vault.getAbstractFileByPath(path)) return;
+    try {
+      await app.vault.createFolder(path);
+    } catch {
+      // ignore
+    }
+  };
+  const upsert = async (path, content) => {
+    let file = app.vault.getAbstractFileByPath(path);
+    if (!file) file = await withTimeout(app.vault.create(path, content), `create ${path}`);
+    else await withTimeout(app.vault.modify(file, content), `modify ${path}`);
+    return file;
+  };
+  const setInlineEdit = async (enabled) => {
+    plugin.settings.inlineEditEnabled = enabled;
+    plugin.settings.inlineEditBlock = true;
+    plugin.settings.inlineEditHeading = false;
+    plugin.settings.inlineEditFile = false;
+    await plugin.saveSettings?.();
+    plugin.inlineEditEngine?.onSettingsChanged?.();
+    await wait(200);
+  };
+  const makeContent = () => {
+    const source = ["# source", ""];
+    for (let i = 1; i <= 48; i += 1) {
+      source.push(`- block ${i} ^i36m${i}`);
+      source.push(`  - child A ${i}`);
+      source.push(`  - child B ${i}`);
+      source.push(`  - child C ${i}`);
+      source.push("");
+    }
+    const host = ["# host", ""];
+    for (let i = 1; i <= 48; i += 1) {
+      host.push(`lead ${i}`);
+      host.push(`![[${sourcePath}#^i36m${i}]]`);
+      host.push(`tail ${i}`);
+      host.push("");
+    }
+    return { source: source.join("\n"), host: host.join("\n") };
+  };
+  const openHost = async () => {
+    const leaf = app.workspace.getLeaf(false);
+    await withTimeout(
+      leaf.setViewState({ type: "markdown", state: { file: hostPath, mode: "source" }, active: true }),
+      "open host"
+    );
+    await waitFor(() => leaf.view?.file?.path === hostPath && leaf.view?.containerEl?.querySelector(".markdown-source-view"));
+    return leaf;
+  };
