+// Temporary CDP probe for BLP-4 / GitHub #36.
+// Instruments inline-edit mount while the host Live Preview editor is already scrolled.
+(async () => {
+  const wait = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
+  const withTimeout = (promise, label, timeoutMs = 12000) =>
+    Promise.race([
+      promise,
+      new Promise((_, reject) => window.setTimeout(() => reject(new Error(`${label} timed out`)), timeoutMs)),
+    ]);
+  const waitFor = async (fn, { timeoutMs = 12000, stepMs = 50 } = {}) => {
+    const started = Date.now();
+    while (Date.now() - started < timeoutMs) {
+      const value = await fn();
+      if (value) return value;
+      await wait(stepMs);
+    }
+    return null;
+  };
+  const pluginId = "block-link-plus";
+  const plugin = app.plugins.plugins[pluginId];
+  if (!plugin) throw new Error("block-link-plus plugin is not loaded");
+
+  const tmpFolder = "_blp_tmp/issue-36-instrumented";
+  const sourcePath = `${tmpFolder}/source.md`;
+  const hostPath = `${tmpFolder}/host.md`;
+  const originalSettings = {
+    inlineEditEnabled: plugin.settings.inlineEditEnabled,
+    inlineEditBlock: plugin.settings.inlineEditBlock,
+    inlineEditHeading: plugin.settings.inlineEditHeading,
+    inlineEditFile: plugin.settings.inlineEditFile,
+  };
+  const previousFile = app.workspace.getActiveFile?.() ?? null;
+  const events = [];
+  const pushEvent = (event) => {
+    events.push({
+      at: Math.round(performance.now()),
+      ...event,
+      stack: String(new Error().stack || "")
+        .split("\n")
+        .slice(2, 7)
+        .join(" | "),
+    });
+  };
+  const ensureFolder = async (path) => {
+    if (app.vault.getAbstractFileByPath(path)) return;
+    try {
+      await app.vault.createFolder(path);
+    } catch {
+      // ignore
+    }
+  };
+  const upsert = async (path, content) => {
+    let file = app.vault.getAbstractFileByPath(path);
+    if (!file) file = await withTimeout(app.vault.create(path, content), `create ${path}`);
+    else await withTimeout(app.vault.modify(file, content), `modify ${path}`);
+    return file;
+  };
+  const setInlineEdit = async (enabled) => {
+    plugin.settings.inlineEditEnabled = enabled;
+    plugin.settings.inlineEditBlock = true;
+    plugin.settings.inlineEditHeading = false;
+    plugin.settings.inlineEditFile = false;
+    await plugin.saveSettings?.();
+    plugin.inlineEditEngine?.onSettingsChanged?.();
+    await wait(200);
+  };
+  const makeContent = () => {
+    const source = ["# source", ""];
+    for (let i = 1; i <= 48; i += 1) {
+      source.push(`- block ${i} ^i36m${i}`);
+      source.push(`  - child A ${i}`);
+      source.push(`  - child B ${i}`);
+      source.push(`  - child C ${i}`);
+      source.push("");
+    }
+    const host = ["# host", ""];
+    for (let i = 1; i <= 48; i += 1) {
+      host.push(`lead ${i}`);
+      host.push(`![[${sourcePath}#^i36m${i}]]`);
+      host.push(`tail ${i}`);
+      host.push("");
+    }
+    return { source: source.join("\n"), host: host.join("\n") };
+  };
+  const openHost = async () => {
+    const leaf = app.workspace.getLeaf(false);
+    await withTimeout(
+      leaf.setViewState({ type: "markdown", state: { file: hostPath, mode: "source" }, active: true }),
+      "open host"
+    );
+    await waitFor(() => leaf.view?.file?.path === hostPath && leaf.view?.containerEl?.querySelector(".markdown-source-view"));
+    return leaf;
+  };
+  const visibleText = (leaf) => {
+    const scroller = leaf.view?.editor?.cm?.scrollDOM;
+    const rect = scroller?.getBoundingClientRect?.();
+    if (!rect) return null;
+    return document.elementFromPoint(rect.left + 40, rect.top + 80)?.textContent?.slice(0, 120) ?? null;
+  };
+  const snapshot = (leaf, label) => {
+    const cm = leaf.view?.editor?.cm;
+    const scroller = cm?.scrollDOM ?? leaf.view?.containerEl?.querySelector(".cm-scroller");
+    const root = leaf.view?.containerEl ?? document;
+    return {
+      label,
+      scrollTop: scroller?.scrollTop ?? null,
+      scrollHeight: scroller?.scrollHeight ?? null,
+      clientHeight: scroller?.clientHeight ?? null,
+      embedCount: root.querySelectorAll(".internal-embed.markdown-embed").length,
+      activeInlineCount: root.querySelectorAll(".internal-embed.markdown-embed.blp-inline-edit-active").length,
+      rootCount: root.querySelectorAll(".blp-inline-edit-root").length,
+      pendingCount: plugin.inlineEditEngine?.livePreviewObservers
+        ? Array.from(plugin.inlineEditEngine.livePreviewObservers.values()).reduce((sum, entry) => sum + entry.pendingEmbeds.size, 0)
+        : null,
+      firstVisibleText: visibleText(leaf),
+    };
+  };
+
+  let editorProto = null;
+  let originalEditorScrollIntoView = null;
+  let cmProto = null;
+  let originalRequestMeasure = null;
+  let originalDispatch = null;
+  let elementProto = null;
+  let originalElementScrollIntoView = null;
+
+  const installInstrumentation = (leaf) => {
+    editorProto = Object.getPrototypeOf(leaf.view.editor);
+    originalEditorScrollIntoView = editorProto.scrollIntoView;
+    if (typeof originalEditorScrollIntoView === "function") {
+      editorProto.scrollIntoView = function patchedScrollIntoView(range, center) {
+        pushEvent({ type: "editor.scrollIntoView", center: center === true, range: JSON.stringify(range ?? null) });
+        return originalEditorScrollIntoView.apply(this, arguments);
+      };
+    }
+
+    cmProto = Object.getPrototypeOf(leaf.view.editor.cm);
+    originalRequestMeasure = cmProto.requestMeasure;
+    if (typeof originalRequestMeasure === "function") {
+      cmProto.requestMeasure = function patchedRequestMeasure() {
+        pushEvent({ type: "cm.requestMeasure", docLines: this?.state?.doc?.lines ?? null });
+        return originalRequestMeasure.apply(this, arguments);
+      };
+    }
+    originalDispatch = cmProto.dispatch;
+    if (typeof originalDispatch === "function") {
+      cmProto.dispatch = function patchedDispatch(spec) {
+        const specs = Array.isArray(spec) ? spec : [spec];
+        if (specs.some((s) => s?.scrollIntoView === true)) {
+          pushEvent({ type: "cm.dispatch.scrollIntoView", count: specs.length });
+        }
+        return originalDispatch.apply(this, arguments);
+      };
+    }
+
+    elementProto = Element.prototype;
+    originalElementScrollIntoView = elementProto.scrollIntoView;
+    if (typeof originalElementScrollIntoView === "function") {
+      elementProto.scrollIntoView = function patchedElementScrollIntoView(arg) {
+        const el = this instanceof HTMLElement ? this : null;
+        pushEvent({
+          type: "element.scrollIntoView",
+          tag: el?.tagName ?? null,
+          cls: el?.className ? String(el.className).slice(0, 120) : "",
+          arg: JSON.stringify(arg ?? null),
+        });
+        return originalElementScrollIntoView.apply(this, arguments);
+      };
+    }
+  };
+  const restoreInstrumentation = () => {
+    try {
+      if (editorProto && originalEditorScrollIntoView) editorProto.scrollIntoView = originalEditorScrollIntoView;
+    } catch {
+      // ignore
+    }
+    try {
+      if (cmProto && originalRequestMeasure) cmProto.requestMeasure = originalRequestMeasure;
+    } catch {
+      // ignore
+    }
+    try {
+      if (cmProto && originalDispatch) cmProto.dispatch = originalDispatch;
+    } catch {
+      // ignore
+    }
+    try {
+      if (elementProto && originalElementScrollIntoView) elementProto.scrollIntoView = originalElementScrollIntoView;
+    } catch {
+      // ignore
+    }
+  };
+
+  try {
+    await ensureFolder("_blp_tmp");
+    await ensureFolder(tmpFolder);
+    const content = makeContent();
+    await upsert(sourcePath, content.source);
+    await upsert(hostPath, content.host);
+
+    await setInlineEdit(false);
+    const leaf = await openHost();
+    const scroller = leaf.view?.editor?.cm?.scrollDOM;
+    if (!scroller) throw new Error("missing host scroller");
+    await waitFor(() => snapshot(leaf, "native-ready").embedCount >= 8, { timeoutMs: 15000 });
+    const max = Math.max(0, scroller.scrollHeight - scroller.clientHeight);
+    scroller.scrollTop = Math.round(max * 0.45);
+    scroller.dispatchEvent(new Event("scroll", { bubbles: true }));
+    await wait(600);
+    const beforeEnable = snapshot(leaf, "before-enable-inline-edit");
+
+    installInstrumentation(leaf);
+    await setInlineEdit(true);
+    plugin.inlineEditEngine?.refreshLivePreviewObservers?.(true);
+    const duringMount = [];
+    for (const delay of [50, 150, 350, 800, 1600, 3000]) {
+      await wait(delay);
+      duringMount.push(snapshot(leaf, `after-enable-plus-${delay}`));
+    }
+    const afterEnable = snapshot(leaf, "after-enable-inline-edit");
+
+    return {
+      ok: true,
+      runtime: {
+        title: document.title,
+        vault: app.vault.getName(),
+        activeFile: app.workspace.getActiveFile?.()?.path ?? null,
+        isMobile: app.isMobile,
+        viewport: { innerWidth, innerHeight },
+      },
+      settingsUsed: {
+        inlineEditEnabled: true,
+        inlineEditBlock: true,
+        inlineEditHeading: false,
+        inlineEditFile: false,
+      },
+      beforeEnable,
+      duringMount,
+      afterEnable,
+      scrollDelta: typeof beforeEnable.scrollTop === "number" && typeof afterEnable.scrollTop === "number"
+        ? afterEnable.scrollTop - beforeEnable.scrollTop
+        : null,
+      eventCounts: events.reduce((acc, event) => {
+        acc[event.type] = (acc[event.type] || 0) + 1;
+        return acc;
+      }, {}),
+      scrollIntoViewEvents: events.filter((event) => event.type.includes("scrollIntoView")).slice(0, 40),
+      pluginMeasureEvents: events
+        .filter((event) => event.type === "cm.requestMeasure" && event.stack.includes("plugin:block-link-plus"))
+        .slice(0, 25),
+      firstEvents: events.slice(0, 30),
+      lastEvents: events.slice(-30),
+    };
+  } finally {
+    restoreInstrumentation();
+    try {
+      plugin.settings.inlineEditEnabled = originalSettings.inlineEditEnabled;
+      plugin.settings.inlineEditBlock = originalSettings.inlineEditBlock;
+      plugin.settings.inlineEditHeading = originalSettings.inlineEditHeading;
+      plugin.settings.inlineEditFile = originalSettings.inlineEditFile;
+      await plugin.saveSettings?.();
+      plugin.inlineEditEngine?.onSettingsChanged?.();
+    } catch {
+      // ignore
+    }
+    try {
+      if (previousFile) await app.workspace.getLeaf(false).openFile(previousFile, { active: true });
+    } catch {
+      // ignore
+    }
+  }
+})();
